import{c as i,Q as a,j as t,m as l}from"./chunks/framework.ByJJFMw8.js";const u=JSON.parse('{"title":"方案对比","description":"","frontmatter":{},"headers":[],"relativePath":"guide/compare.md","filePath":"guide/compare.md","lastUpdated":1782401177000}'),r={name:"guide/compare.md"};function d(o,e,h,n,c,f){return a(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="方案对比" tabindex="-1">方案对比 <a class="header-anchor" href="#方案对比" aria-label="Permalink to &quot;方案对比&quot;">​</a></h1><p>File Viewer 的定位是企业后台、内网和私有化场景里的纯前端文件预览组件。它适合“业务附件快速查看、初筛、检索、打印、导出和自托管交付”，但不替代专业编辑器，也不承诺把所有复杂文件做到像原生软件一样高还原。</p><h2 id="和服务端转码方案的差异" tabindex="-1">和服务端转码方案的差异 <a class="header-anchor" href="#和服务端转码方案的差异" aria-label="Permalink to &quot;和服务端转码方案的差异&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方案</th><th>优点</th><th>局限</th></tr></thead><tbody><tr><td>服务端转码</td><td>可统一输出 PDF / 图片，便于缓存、归档和权限审计；对复杂 Office 场景更容易做统一兜底</td><td>需要部署转换服务、队列、临时文件、字体、缓存、重试和清理流程；内网交付成本高</td></tr><tr><td>Office Online / 云服务</td><td>效果好，维护少，协作能力成熟</td><td>内网、私有化、涉密文件、离线环境和严格合规场景不一定适合</td></tr><tr><td>File Viewer</td><td>纯前端、自托管、按需加载，适合嵌入业务系统和内网附件中心</td><td>复杂 Office / CAD 仍需要真实文件回归，不替代专业编辑器或最终归档转换</td></tr></tbody></table><h2 id="什么时候优先选-file-viewer" tabindex="-1">什么时候优先选 File Viewer <a class="header-anchor" href="#什么时候优先选-file-viewer" aria-label="Permalink to &quot;什么时候优先选 File Viewer&quot;">​</a></h2><ul><li>文件不适合传到第三方转换服务。</li><li>项目在内网、私有化、离线或严格 CSP 环境中运行。</li><li>团队希望用同一个组件覆盖 Office、PDF/OFD、CAD、压缩包、邮件、图片、音视频、代码和结构化数据。</li><li>业务目标是“预览、初筛、搜索、打印、导出、下载”，而不是在线编辑。</li><li>前端团队希望按需装配 renderer，而不是在每个页面维护一堆独立 viewer。</li></ul><h2 id="什么时候服务端转码更合适" tabindex="-1">什么时候服务端转码更合适 <a class="header-anchor" href="#什么时候服务端转码更合适" aria-label="Permalink to &quot;什么时候服务端转码更合适&quot;">​</a></h2><ul><li>需要长期归档，且必须把所有文件统一固化为 PDF 或图片。</li><li>文件体积很大，浏览器端内存和移动端性能成为主要瓶颈。</li><li>需要极高还原度、批量转换、OCR、水印固化、合规留痕或异步审核队列。</li><li>业务已经有稳定的 LibreOffice / OnlyOffice / 商业转换服务，并且运维成本可接受。</li></ul><h2 id="推荐组合" tabindex="-1">推荐组合 <a class="header-anchor" href="#推荐组合" aria-label="Permalink to &quot;推荐组合&quot;">​</a></h2><p>很多生产系统可以把两类方案组合起来:</p><ul><li>默认用 File Viewer 做浏览器端即时预览，减少排队和后端转换压力。</li><li>对少数归档、合同、审计或强一致场景，再触发服务端转 PDF。</li><li>内网部署时把 Worker、WASM、字体和 vendor 资源随业务静态资源一起自托管。</li><li>用 issue 和样本回归持续收集真实格式兼容性，而不是只靠合成样例判断效果。</li></ul><h2 id="验证清单" tabindex="-1">验证清单 <a class="header-anchor" href="#验证清单" aria-label="Permalink to &quot;验证清单&quot;">​</a></h2><ul><li>在 <a href="https://demo.file-viewer.app" target="_blank" rel="noreferrer">Demo</a> 试 Word、Excel、PPT、PDF、DWG、ZIP 和 EML。</li><li>用脱敏业务文件验证你真正关心的格式。</li><li>检查移动端 WebView、内网静态资源路径、Worker/WASM MIME、CSP 和字体资源。</li><li>对 Office / CAD 高还原需求，结合 <a href="./format-fidelity">格式完整度</a> 看清楚边界。</li></ul>',13)])])}const m=i(r,[["render",d]]);export{u as __pageData,m as default};
